input.command:
$ErrorActionPreference = 'Stop'
$cred = ("protocol=https`nhost=github.com`n`n" | git credential fill)
$pwLine = $cred | Where-Object { $_ -like 'password=*' }
if (-not $pwLine) { Write-Output 'NO_TOKEN_FOUND'; exit 1 }
$token = $pwLine.Substring(9)
$payload = @{
  title = 'Add the Situation Room: dynamic crisis-simulation finale'
  head  = 'situation-room'
  base  = 'add-final-diagnostic-quiz'
  body  = (Get-Content -Raw .git/PR_BODY.md)
  draft = $false
} | ConvertTo-Json -Depth 5
$headers = @{ Authorization = "Bearer $token"; 'User-Agent' = 'cursor-agent'; Accept = 'application/vnd.github+json' }
try {
  $resp = Invoke-RestMethod -Method Post -Uri 'https://api.github.com/repos/trilogy-group/problem-solving-coach/pulls' -Headers $headers -Body $payload -ContentType 'application/json'
  Write-Output ("PR_CREATED " + $resp.html_url)
} catch {
  Write-Output ("ERROR " + $_.Exception.Message)
  if ($_.ErrorDetails.Message) { Write-Output $_.ErrorDetails.Message }
}

